import React from "react";
import "../App.css";

const Features = () => {
  const features = [
    {
      title: "News",
      description:
        "Stay updated with the latest company announcements and internal updates.",
      icon: "📰",
    },
    {
      title: "Leaves / Attendance",
      description:
        "Track employee attendance and manage leave requests easily in one place.",
      icon: "📅",
    },
    {
      title: "Location Based Employee",
      description:
        "Monitor employee locations and manage teams working from different places.",
      icon: "📍",
    },
  ];

  return (
    <div className="features-page">
      <div className="features-header">
        <h1>Features</h1>
        <h3>Employee / Staff Management</h3>
        <p>
          Manage your employees efficiently with attendance tracking, leave
          management and location based monitoring.
        </p>
      </div>

      <div className="features-container">
        {features.map((feature, index) => (
          <div className="feature-card" key={index}>
            <div className="feature-icon">{feature.icon}</div>

            <h3>{feature.title}</h3>

            <p>{feature.description}</p>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Features;
